import{_ as i,o as s,c as a,a3 as t}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Process & Validation","description":"","frontmatter":{"title":"Process & Validation"},"headers":[],"relativePath":"advertisers/display-email/workflow.md","filePath":"advertisers/display-email/workflow.md"}'),r={name:"advertisers/display-email/workflow.md"};function n(o,e,l,d,p,u){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="workflow-de-campagne" tabindex="-1">Workflow de Campagne <a class="header-anchor" href="#workflow-de-campagne" aria-label="Permalink to &quot;Workflow de Campagne&quot;">​</a></h1><p>Le déploiement d&#39;un encart newsletter est rapide. Voici les étapes de la soumission à la diffusion.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Envoi des éléments créatifs</h3><p>Transmettez au distributeur (via la plateforme getinside) :</p><ul><li><strong>Le visuel</strong> — une image JPG, PNG ou GIF respectant les <a href="./specs">spécifications techniques</a>.</li><li><strong>Le lien de destination</strong> — l&#39;URL de la landing page vers laquelle rediriger les clics.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Configuration du Tracking</h3><p>L&#39;équipe getinside génère un <strong>lien de redirection tracké unique</strong> (format <code>gtinsi.de</code>) et le transmet au distributeur. Ce lien comptabilise chaque clic sur votre bannière.</p><p>Pour mesurer les ventes dans Google Analytics, ajoutez des paramètres UTM à votre URL finale :<br><code>monsite.com?utm_source=getinside&amp;utm_medium=display-email&amp;utm_campaign=printemps</code></p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Intégration et Validation (BAT)</h3><p>Le distributeur intègre votre image dans sa newsletter et vous envoie un BAT (Bon à Tirer) pour prévisualisation.</p><p>Vérifiez le rendu — notamment sur mobile — puis validez sur la plateforme.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Action requise pour débloquer l&#39;envoi</p><ol><li>Connectez-vous sur <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>.</li><li>Ouvrez la campagne concernée.</li><li>Cliquez sur le bouton <strong>&quot;Valider la campagne&quot;</strong>.</li></ol><p>Tant que vous ne validez pas, la newsletter ne sera pas envoyée.</p></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>Diffusion</h3><p>Une fois les deux validations enregistrées (annonceur + distributeur), la newsletter est envoyée à la date prévue. Suivez les clics en temps réel depuis votre tableau de bord.</p></div></div>',8)])])}const v=i(r,[["render",n]]);export{m as __pageData,v as default};
